const query = String($input.first().json.query?.q || '').trim();
const limitRaw = Number.parseInt(String($input.first().json.query?.limit || '20'), 10);
const limit = Number.isFinite(limitRaw) ? Math.min(Math.max(limitRaw, 1), 50) : 20;

return [{
  json: {
    query,
    queryLower: query.toLowerCase(),
    limit,
  },
}];

const params = $('Build Search Params').first().json || {};
const query = String(params.query || '').trim();
const queryLower = String(params.queryLower || '').trim();
const limit = Math.min(Math.max(Number(params.limit) || 20, 1), 50);

if (!query || query.length < 2 || !queryLower) {
  return [];
}

const toStringSafe = (value) => {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
};

const normalizeText = (value) => toStringSafe(value).replace(/\s+/g, ' ').trim();

const pad2 = (value) => String(value).padStart(2, '0');

const parseDate = (raw) => {
  const text = normalizeText(raw);
  if (!text) return null;
  if (/^\d{4}-\d{2}-\d{2}/.test(text)) return text.slice(0, 10);

  const parts = text.split('/').map((part) => Number(part.trim()));
  if (parts.length !== 3 || parts.some((part) => Number.isNaN(part))) return null;

  const [day, month, yearRaw] = parts;
  if (!day || !month || !yearRaw) return null;
  const year = yearRaw < 100 ? 2000 + yearRaw : yearRaw;
  return `${year}-${pad2(month)}-${pad2(day)}`;
};

const parseTime = (raw) => {
  const text = normalizeText(raw);
  if (!text) return null;

  const parts = text.split(':').map((part) => Number(part.trim()));
  if (parts.length < 2 || parts.length > 3 || parts.some((part) => Number.isNaN(part))) return null;

  const [hour, minute, second = 0] = parts;
  if (hour < 0 || hour > 23 || minute < 0 || minute > 59 || second < 0 || second > 59) return null;
  return `${pad2(hour)}:${pad2(minute)}:${pad2(second)}`;
};

const extractDatetime = (message) => {
  const direct = normalizeText(message?.datetime);
  if (direct && !Number.isNaN(new Date(direct).getTime())) {
    return new Date(direct).toISOString();
  }

  const metadata = message?.data?.response_metadata || {};
  const isHuman = normalizeText(message?.type).toLowerCase() === 'human';
  const dateRaw = (isHuman ? metadata.human_date : metadata.ai_date) || metadata.date || metadata.message_date;
  const timeRaw = (isHuman ? metadata.human_time : metadata.ai_time) || metadata.time || metadata.message_time;

  const isoDate = parseDate(dateRaw);
  const isoTime = parseTime(timeRaw);
  if (!isoDate || !isoTime) return null;

  const merged = `${isoDate}T${isoTime}`;
  return Number.isNaN(new Date(merged).getTime()) ? null : new Date(merged).toISOString();
};

const getMessageContent = (message) => {
  const type = normalizeText(message?.type).toLowerCase();

  if (type === 'tool') {
    const toolName = normalizeText(message?.data?.tool_call?.name || message?.data?.tool_response?.name || message?.name);
    const toolContent = normalizeText(message?.data?.tool_response?.content || message?.data?.content || message?.content);
    return normalizeText(`${toolName} ${toolContent}`);
  }

  const primary = normalizeText(message?.data?.content || message?.content);
  if (primary) return primary;

  const fallback = normalizeText(message?.data?.tool_response?.content);
  return fallback;
};

const hits = [];
for (const item of $input.all()) {
  const sessionId = normalizeText(item.json.sessionId);
  if (!sessionId) continue;

  const messages = Array.isArray(item.json.messages) ? item.json.messages : [];
  for (const message of messages) {
    const content = getMessageContent(message);
    if (!content) continue;

    if (!content.toLowerCase().includes(queryLower)) continue;

    const datetime = extractDatetime(message);
    hits.push({
      sessionId,
      userId: sessionId,
      content,
      excerpt: content.length > 140 ? `${content.slice(0, 140).trimEnd()}...` : content,
      datetime,
    });
  }
}

hits.sort((a, b) => {
  const aTs = a.datetime ? new Date(a.datetime).getTime() : 0;
  const bTs = b.datetime ? new Date(b.datetime).getTime() : 0;
  return bTs - aTs;
});

return hits.slice(0, limit).map((hit) => ({ json: hit }));
